import React, { useCallback, useMemo, useState, useEffect } from 'react';
import { 
  Box, 
  Grid, 
  Paper, 
  IconButton,
  Tooltip
} from '@mui/material';
import FAWTypography from '../../FAWTypography';
import FAWSkeleton from '../../FAWSkeleton';
import FAWLoader from '../../FAWLoader';
import { Edit as EditIcon, Save as SaveIcon } from '@mui/icons-material';
import FAWDrawer from '../../FAWDrawer';
import FAWToast from '../../FAWToast';
import FAWErrorBoundary from '../../errorHandling/FAWErrorBoundary';
import FAWModal from '../../FAWModal';
import EditContentForm from './EditContentForm';
import { useEditContentState } from '../hooks/useEditContentState';
import { useEditContentHandlers } from '../hooks/useEditContentHandlers';
import '../styles/notifications.css';

const EditContentDrawer = ({ 
  open = false, 
  onClose, 
  onSuccess, 
  notificationData = {},
  selectedNotificationType = null,
  languageOptions = []
}) => {
  // State for refDomains (template variables)
  const [refDomains, setRefDomains] = useState([]);

  const loadTemplateVariables = useCallback(async (notificationDefinition) => {
    if (!notificationDefinition) {
      return [];
    }
    const response = await fetch(
      `/Notification/GetTemplateVariables?notificationDefinition=${encodeURIComponent(notificationDefinition)}`,
      {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json; charset=utf-8'
        }
      }
    );
    if (!response.ok) {
      throw new Error('Failed to load template variables');
    }
    const data = await response.json();
    if (!data?.IsSuccess || !Array.isArray(data.TemplateVariables)) {
      return [];
    }
    return data.TemplateVariables;
  }, []);
  
  // Initialize refDomains when drawer opens or notification type changes
  useEffect(() => {
  
    if (open && selectedNotificationType?.value) {
       
      loadTemplateVariables(selectedNotificationType.value)
        .then((templateVariables) => {
          if (!Array.isArray(templateVariables) || templateVariables.length === 0) {
            setRefDomains([]);
            return;
          }
          setRefDomains([
            {
              Name: 'TemplateVariables',
              Description: 'Template Variables',
              RefCodes: templateVariables
                .filter(item => item && item.Code)
                .map(item => ({
                  Code: item.Code,
                  Meaning: item.Meaning || item.Description || item.Code,
                  Description: item.Description || item.Meaning || item.Code
                }))
            }
          ]);
        })
        .catch((error) => {
          console.error('Error loading template variables:', error);
          setRefDomains([]);
        });
    }
  }, [open, selectedNotificationType?.value, loadTemplateVariables]);
  
  // Use custom hooks for state management and handlers
  const state = useEditContentState({    open, 
    onClose, 
    onSuccess, 
    notificationData, 
    selectedNotificationType,
    languageOptions
  });
  const handlers = useEditContentHandlers({
    onClose,
    onSuccess,
    notificationData,
    selectedNotificationType,
    languageOptions,
    formRef: state.formRef,
    setSaving: state.setSaving,
    setToast: state.setToast,
    setDrawerOpen: state.setDrawerOpen,
    setError: state.setError,
    setConfirmationDialog: state.setConfirmationDialog
  });

  // Handle language change - reload notification content for the new language
    const handleLanguageChange = useCallback(async (newLanguage) => {
    if (!selectedNotificationType?.value || !newLanguage) {
      return;
    }

    try {
      state.setLoading(true);
      state.setError(null);

      // Load notification definition for the new language
      const response = await fetch(
        `/Notification/LoadNotificationDefinition?notificationDefinition=${encodeURIComponent(selectedNotificationType.value)}&selectedLanguage=${encodeURIComponent(newLanguage)}`,
        {
          method: 'GET',
          headers: {
            'Content-Type': 'application/json; charset=utf-8'
          }
        }
      );

      if (!response.ok) {
        throw new Error(`Failed to load notification content for language: ${newLanguage}`);
      }

      const htmlContent = await response.text();
      const tempDiv = document.createElement('div');
      tempDiv.innerHTML = htmlContent;

      const templateVariables = await loadTemplateVariables(selectedNotificationType.value);
      if (!Array.isArray(templateVariables) || templateVariables.length === 0) {
        setRefDomains([]);
      } else {
        setRefDomains([
          {
            Name: 'TemplateVariables',
            Description: 'Template Variables',
            RefCodes: templateVariables
              .filter(item => item && item.Code)
              .map(item => ({
                Code: item.Code,
                Meaning: item.Meaning || item.Description || item.Code,
                Description: item.Description || item.Meaning || item.Code
              }))
          }
        ]);
      }

      // Extract values using the same logic as in Notifications.cshtml
      const extractValue = (container, fieldName) => {
         
          if (fieldName === 'ActiveIn') {
              const checkbox = container.querySelector(`input[id*="${fieldName}"][type="checkbox"]`);
             
          if (checkbox) {
            return checkbox.checked ? 'true' : 'false';
          }
          const hidden = container.querySelector(`input[name*="${fieldName}"][type="hidden"]`);
          if (hidden) {
            return hidden.value;
          }
        }
        
        const element = container.querySelector(`[name*="${fieldName}"], [id*="${fieldName}"]`);
        if (element) {
          if (element.tagName === 'INPUT' || element.tagName === 'TEXTAREA' || element.tagName === 'SELECT') {
            return element.value;
          } else {
            return element.textContent || element.innerText;
          }
        }
        return null;
      };

      const activeValue = extractValue(tempDiv, 'ActiveIn');
        const subject = extractValue(tempDiv, 'SubjectContent') || '';

      // Extract message content
      // The HTML from LoadNotificationDefinition contains a textarea with the message content
      let message = '';
      const messageTextarea = tempDiv.querySelector('#MessageContent, textarea[name*="MessageContent"], textarea[id*="MessageContent"]');
      if (messageTextarea) {
        message = messageTextarea.value || messageTextarea.textContent || messageTextarea.innerText || '';
      }
      
      // If no message found, try to get from any textarea in the form
      if (!message) {
        const allTextareas = tempDiv.querySelectorAll('textarea');
        for (let i = 0; i < allTextareas.length; i++) {
          const textarea = allTextareas[i];
          const value = textarea.value || textarea.textContent || textarea.innerText || '';
          if (value && value.trim().length > 0) {
            message = value;
            break;
          }
        }
      }

      // Ensure we're using the language code, not the display name
      // newLanguage should already be the code from FAWSelect, but let's ensure it
      let languageCodeToUse = newLanguage;
      if (languageOptions && languageOptions.length > 0) {
        const matchingOption = languageOptions.find(opt => 
          opt.value === newLanguage || opt.label === newLanguage
        );
        if (matchingOption) {
          languageCodeToUse = matchingOption.value; // Always use the code
        }
      }

      // Update form data with the new language-specific values (use code, not label)
      if (state.formRef.current && state.formRef.current.setFormData) {
        state.formRef.current.setFormData({
          Language: languageCodeToUse,
          EmailSubject: subject,
          MessageContent: message,
          Active: activeValue === 'true'
        });
      }

      // Update initialData so the form reflects the changes (use code, not label)
      state.setInitialData({
        Language: languageCodeToUse,
        ScheduleFrequency: state.initialData.ScheduleFrequency || 'Run Only Once',
        EmailSubject: subject,
        MessageContent: message,
        Active: activeValue === 'true'
      });

      // Update global currentNotificationData if it exists (this is acceptable as it's a global object, not a prop)
      if (typeof window !== 'undefined' && window.currentNotificationData) {
        window.currentNotificationData.language = languageCodeToUse;
        window.currentNotificationData.subject = subject;
        window.currentNotificationData.message = message;
        window.currentNotificationData.isActive = activeValue === 'true';
      }

    } catch (error) {
      console.error('Error loading notification content for language:', error);
      state.setToast({
        open: true,
        message: `Error loading content for ${newLanguage}. Please try again.`,
        type: 'error',
        duration: 5000
      });
    } finally {
      state.setLoading(false);
    }
  }, [selectedNotificationType, state.setLoading, state.setError, state.setToast, state.formRef, state.setInitialData, state.initialData, languageOptions, notificationData]);

  // Define drawer actions with useMemo to prevent unnecessary re-renders
  const drawerActions = useMemo(() => {
    return [
      {
        text: 'Cancel',
        variant: 'outlined',
        onClick: (e) => {
          e?.preventDefault?.();
          e?.stopPropagation?.();
          handlers.handleCancel();
        },
        disabled: state.saving,
        handlerType: 'custom', // Bypass form submission for custom handlers
        type: 'button' // Ensure button doesn't submit form
      },
      {
        text: state.saving ? 'Saving...' : 'Save',
        variant: 'contained',
        color: 'primary',
        onClick: (e) => {
          return handlers.handleSaveClick(e);
        },
        disabled: state.saving,
        handlerType: 'custom', // Bypass form submission for custom handlers
        componentType: 'editcontent', // Special identifier for edit content
        startIcon: <SaveIcon />,
        type: 'button' // Ensure button doesn't submit form
      }
    ];
  }, [handlers.handleCancel, handlers.handleSaveClick, state.saving]);

  // Memoize confirmation dialog content and actions to prevent unnecessary re-renders
  const confirmationContent = useMemo(() => {
    return (
      <Box sx={{ p: 2 }}>
        <FAWTypography variant="body1">
          {state.confirmationDialog.message}
        </FAWTypography>
      </Box>
    );
  }, [state.confirmationDialog.message]);

  const confirmationActions = useMemo(() => {
    return [
      {
        label: state.confirmationDialog.cancelText || 'Cancel',
        onClick: (e) => {
          return state.confirmationDialog.onCancel?.(e);
        },
        variant: 'outlined',
        color: 'secondary'
      },
      {
        label: state.confirmationDialog.confirmText || 'Save',
        onClick: (e) => {
          return state.confirmationDialog.onConfirm?.(e);
        },
        variant: 'contained',
        color: state.confirmationDialog.severity === 'error' ? 'error' : 'primary'
      }
    ];
  }, [
    state.confirmationDialog.cancelText,
    state.confirmationDialog.confirmText,
    state.confirmationDialog.onCancel,
    state.confirmationDialog.onConfirm,
    state.confirmationDialog.severity
  ]);

  return (
    <FAWErrorBoundary
      title="Edit Content Error"
      message="An error occurred while loading the edit content form. Please try again or contact support if the problem persists."
      showDetails={true}
      onError={(error, errorInfo) => {
        console.error('EditContentDrawer Error:', error, errorInfo);
      }}
      onReportError={(error) => {
        // Error reported by user
      }}
    >
      <Box className="edit-content-drawer-container">
        {/* Atlas Toast for notifications */}
        <FAWToast 
          className="edit-content-drawer-toast"
          open={state.toast.open} 
          message={state.toast.message} 
          type={state.toast.type} 
          duration={state.toast.duration}
          onClose={handlers.handleToastClose} 
        />

        {/* Confirmation Dialog */}
        <FAWModal
          open={state.confirmationDialog.open}
          title={state.confirmationDialog.title}
          content={confirmationContent}
          actions={confirmationActions}
          onClose={state.confirmationDialog.onCancel}
        />

        {/* Main Drawer - Contains the form for editing notification content */}
        <FAWDrawer
          className="edit-content-drawer"
          open={state.drawerOpen}
          onClose={handlers.handleCloseDrawer}
          title="Edit notification content"
          width={600}
          anchor="right"
          variant="temporary"
          showCloseButton={true}
          showHeader={true}
          customFooter={true}
          actions={drawerActions}
        >
          <Box sx={{ position: 'relative', height: '100%' }}>
            {/* Saving overlay */}
            {state.saving && (
              <Box
                sx={{
                  position: 'absolute',
                  top: 0,
                  left: 0,
                  right: 0,
                  bottom: 0,
                  backgroundColor: 'rgba(255, 255, 255, 0.8)',
                  display: 'flex',
                  justifyContent: 'center',
                  alignItems: 'center',
                  zIndex: 10,
                  backdropFilter: 'blur(2px)'
                }}
              >
                <FAWLoader size={40} label="Saving..." />
              </Box>
            )}
            
            {state.loading ? (
              <Box className="edit-content-drawer-loading" sx={{ p: 3 }}>
                <FAWSkeleton variant="form" />
              </Box>
            ) : (
              <EditContentForm
                ref={state.formRef}
                onSave={handlers.handleSaveClick}
                onCancel={handlers.handleCancel}
                initialData={state.initialData}
                saving={state.saving}
                notificationData={notificationData}
                selectedNotificationType={selectedNotificationType}
                languageOptions={languageOptions}
                onLanguageChange={handleLanguageChange}
                refDomains={refDomains}
              />
            )}
          </Box>
        </FAWDrawer>
      </Box>
    </FAWErrorBoundary>
  );
};

export default EditContentDrawer;
