import { useCallback } from 'react';

/**
 * Custom hook for managing EditContentDrawer handlers
 * Extracts all handler logic to make the component more modular
 */
export const useEditContentHandlers = ({
  onClose,
  onSuccess,
  notificationData,
  selectedNotificationType,
  languageOptions,
  formRef,
  setSaving,
  setToast,
  setDrawerOpen,
  setError,
  setConfirmationDialog
}) => {

  // Handle drawer close
  const handleCloseDrawer = useCallback(() => {
    setDrawerOpen(false);
    if (onClose) {
      onClose();
    }
  }, [onClose, setDrawerOpen]);

  // Handle cancel action
  const handleCancel = useCallback(() => {
    setDrawerOpen(false);
    if (onClose) {
      onClose();
    }
  }, [onClose, setDrawerOpen]);

  // Handle toast close
  const handleToastClose = useCallback(() => {
    setToast(prev => ({ ...prev, open: false }));
  }, [setToast]);

  // Get CSRF token from the page
  const getCsrfToken = useCallback(() => {
    // Try to get the token from the hidden input field on the page
    const tokenInput = document.querySelector('input[name="__RequestVerificationToken"]');
    if (tokenInput && tokenInput.value) {
      return tokenInput.value;
    }
    
    console.error('CSRF token not found on page');
    return null;
  }, []);

  // Handle save edit content
  const handleSaveClick = useCallback(async () => {
    try {
      setSaving(true);
      setError(null);

      // Get form data using the form component's exposed methods
      let formData = {};
      if (formRef.current && formRef.current.getFormData) {
        formData = formRef.current.getFormData();
      }
      
      // If React form data is empty, try to get from DOM as fallback
      if (!formData || Object.keys(formData).length === 0) {
        const form = document.querySelector('#edit-content-drawer form');
        if (form) {
          const formElements = form.elements;
          for (let i = 0; i < formElements.length; i++) {
            const element = formElements[i];
            if (element.name && element.type !== 'submit' && element.type !== 'button') {
              if (element.type === 'checkbox') {
                formData[element.name] = element.checked;
              } else {
                formData[element.name] = element.value;
              }
            }
          }
        }
      }

      // Validate form data
      if (formRef.current && formRef.current.validateForm) {
        const isValid = formRef.current.validateForm();
        if (!isValid) {
          setToast({
            open: true,
            message: 'Please fix the validation errors before saving',
            type: 'error',
            duration: 3000
          });
          setSaving(false);
          return;
        }
      }
      // Also try to get form data from DOM as fallback (matching original implementation)
      let domFormData = {};
      try {
        const form = document.querySelector('#edit-content-drawer form');
        if (form) {
          const formElements = form.elements;
          for (let i = 0; i < formElements.length; i++) {
            const element = formElements[i];
            if (element.name && element.type !== 'submit' && element.type !== 'button') {
              if (element.type === 'checkbox') {
                domFormData[element.name] = element.checked;
              } else {
                domFormData[element.name] = element.value;
              }
            }
          }
        }
      } catch (error) {
        console.error('Could not extract DOM form data:', error);
      }

      // Get CSRF token from the page
      const csrfToken = getCsrfToken();
      if (!csrfToken) {
        setToast({
          open: true,
          message: 'Security token not found. Please refresh the page and try again.',
          type: 'error',
          duration: 5000
        });
        setSaving(false);
        return;
      }

      // Get language code - formData.Language should already be the code from languageOptions
      // languageOptions come from server RefCodes where value = RefCode.Code (e.g., "EN", "ES", "FR")
      // If formData.Language is already a code format, use it directly
      // Otherwise, look it up in languageOptions by label
      let languageCode = formData.Language || 'EN';
      
      // If languageOptions are available and formData.Language doesn't look like a code, try to find it
      if (languageOptions && languageOptions.length > 0 && formData.Language) {
        // Check if it's already a code (2-3 uppercase letters)
        const isCodeFormat = /^[A-Z]{2,3}$/.test(formData.Language);
        
        if (!isCodeFormat) {
          // It's likely a display name, find the corresponding code from languageOptions
          const matchingOption = languageOptions.find(opt => 
            opt.label?.toLowerCase() === formData.Language?.toLowerCase() ||
            opt.value?.toLowerCase() === formData.Language?.toLowerCase()
          );
          
          if (matchingOption) {
            languageCode = matchingOption.value;
          }
        }
        // If it's already a code format, use it as-is
      }

      // Prepare the payload for saving notification content (matching the original form structure exactly)
      // Use the exact field names that the server's NotificationDefinitionModel expects
      // IMPORTANT: @Html.CheckBoxFor generates TWO fields - a hidden field (always false) and the checkbox (true when checked)
      // We need to use URLSearchParams to handle duplicate keys properly
      const urlSearchParams = new URLSearchParams();
      // Add all the standard fields
      urlSearchParams.append('__RequestVerificationToken', csrfToken);
      urlSearchParams.append('CanFrequencyChange', 'False');
      urlSearchParams.append('SelectedNotificationDefinitionType', selectedNotificationType?.value || '');
      urlSearchParams.append('SelectedTemplateLanguage', languageCode);
      urlSearchParams.append('SelectedScheduleTypes', formData.ScheduleFrequency || 'Run Only Once');
      urlSearchParams.append('SubjectContent', formData.EmailSubject || '');
      urlSearchParams.append('MessageContent', formData.MessageContent || '');
      urlSearchParams.append('ExistingNotificationTypeNamesJson', '[]');
      urlSearchParams.append('notification-type-name', '');
      urlSearchParams.append('TestEmailRecipientEmailAddress', '');

      urlSearchParams.append('ActiveIn', String(!!formData.Active));
      // Make AJAX call to save notification content (matching original implementation) 
      // Note: X-Requested-With header is required for ASP.NET MVC to recognize this as an AJAX request
      // Convert URLSearchParams to FormData (don't include token in body, send as header)
      const submitFormData = new FormData();
      for (const [key, value] of urlSearchParams.entries()) {
        if (key !== '__RequestVerificationToken') {
          submitFormData.append(key, value);
        }
      }
      
      const response = await fetch('/Notification/SaveNotification', {
        method: 'POST',
        headers: {
          'X-Requested-With': 'XMLHttpRequest', // Required for Request.IsAjaxRequest() to return true
          '__RequestVerificationToken': csrfToken // Send token as header
        },
        body: submitFormData,
        credentials: 'include'
      });

      // Check response content type before parsing
      const contentType = response.headers.get('content-type');
      const isJson = contentType && contentType.includes('application/json');

      let result;
      
      if (isJson) {
        // Parse as JSON
        if (!response.ok) {
          const errorData = await response.json().catch(() => ({}));
          throw new Error(errorData.Message || `HTTP error! status: ${response.status}`);
        }
        result = await response.json();
      } else {
        // Server returned HTML (likely an error page or redirect)
        const htmlText = await response.text();
        console.error('Server returned HTML instead of JSON:', htmlText.substring(0, 500));
        
        // Try to extract error message from HTML if possible
        let errorMessage;
        if (!response.ok) {
          errorMessage = `Server error (${response.status}). Please check the console for details.`;
        } else {
          errorMessage = 'Server returned unexpected response format. Please try again.';
        }
        
        throw new Error(errorMessage);
      }
      if (result.IsSuccess) {
        setToast({
          open: true,
          message: 'Notification content saved successfully!',
          type: 'success',
          duration: 5000
        });
        
        // Update global currentNotificationData so the notifications list UI can refresh
        if (typeof window !== 'undefined') {
          const persisted = result.Persisted;
          if (persisted) {
            window.currentNotificationData = window.currentNotificationData || {};
            window.currentNotificationData.language = persisted.SelectedTemplateLanguage ?? languageCode;
            window.currentNotificationData.subject = persisted.SubjectContent ?? formData.EmailSubject ?? '';
            window.currentNotificationData.message = persisted.MessageContent ?? formData.MessageContent ?? '';
            window.currentNotificationData.isActive = persisted.ActiveIn === true;
            window.currentNotificationData.scheduleFrequency = persisted.SelectedScheduleTypes ?? window.currentNotificationData.scheduleFrequency;
          } else {
            window.currentNotificationData = window.currentNotificationData || {};
            window.currentNotificationData.language = languageCode;
            window.currentNotificationData.subject = formData.EmailSubject || '';
            window.currentNotificationData.message = formData.MessageContent || '';
            window.currentNotificationData.isActive = formData.Active === true;
          }
        }
        
        // Call success callback if provided - this should trigger a refresh of the list UI
        if (onSuccess) {
          onSuccess(result);
        }
        
        // Close drawer after successful save - ensure onClose is called
        setDrawerOpen(false);
        if (onClose) {
          onClose();
        }
      } else {
        setToast({
          open: true,
          message: `Error: ${result.Message || 'Failed to save notification content'}`,
          type: 'error',
          duration: 5000
        });
      }

    } catch (error) {
      console.error('Error saving notification content:', error);
      setToast({
        open: true,
        message: 'Error saving notification content. Please try again.',
        type: 'error',
        duration: 5000
      });
      setError(error.message);
    } finally {
      setSaving(false);
    }
  }, [
    formRef,
    selectedNotificationType,
    notificationData,
    setSaving,
    setToast,
    setError,
    setDrawerOpen,
    onClose,
    onSuccess,
    getCsrfToken,
    languageOptions
  ]);

  return {
    handleCloseDrawer,
    handleCancel,
    handleSaveClick,
    handleToastClose
  };
};
