import React, { forwardRef, useImperativeHandle, useState, useEffect } from 'react';
import { 
  Box, 
  Grid, 
  Paper, 
  Typography,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  FormControlLabel,
  Checkbox,
  Alert
} from '@mui/material';
import FAWInput from '../../FAWInput';
import FAWDropdown from '../../FAWDropdown';
import FAWCheckbox from '../../FAWCheckbox';
import FAWTextEditor from '../../FAWTextEditor';
import FAWTextarea from '../../FAWTextarea';
import FAWTypography from '../../FAWTypography';
import RequiredIndicator from '../../RequiredIndicator';
import '../styles/notifications.css';

const EditContentForm = forwardRef(({
  onSave,
  onCancel,
  initialData = {},
  saving = false,
  notificationData = {},
  selectedNotificationType = null,
  languageOptions = [],
  onLanguageChange = null,
  refDomains = []
}, ref) => {
  const [formData, setFormDataState] = useState({
    Language: initialData.Language || notificationData.language || 'EN',
    ScheduleFrequency: initialData.ScheduleFrequency || notificationData.scheduleFrequency || 'Run Only Once',
    EmailSubject: (initialData.EmailSubject || notificationData.subject || '') === '0' ? '' : (initialData.EmailSubject || notificationData.subject || ''),
    Active: notificationData.isActive,
    MessageContent: initialData.MessageContent || notificationData.message || ''
  });

  const [errors, setErrors] = useState({});

  // Update form data when initialData or notificationData changes
    useEffect(() => {
    const emailSubject = initialData.EmailSubject || notificationData.subject || '';
      const newFormData = {
        Language: initialData.Language || notificationData.language || 'EN',
        ScheduleFrequency: initialData.ScheduleFrequency || notificationData.scheduleFrequency || 'Run Only Once',
        EmailSubject: emailSubject === '0' ? '' : emailSubject,
        Active: initialData.Active !== undefined ? initialData.Active : (notificationData.isActive === true),
        MessageContent: initialData.MessageContent || notificationData.message || ''
      };
    setFormDataState(newFormData);
  }, [initialData, notificationData]);

  // Expose methods to parent component
  useImperativeHandle(ref, () => ({
    getFormData: () => formData,
    setFormData: (newData) => {
      setFormDataState(prevFormData => ({
        ...prevFormData,
        ...newData
      }));
    },
    validateForm: () => {
      const newErrors = {};
      
      if (!formData.EmailSubject || formData.EmailSubject.trim() === '') {
        newErrors.EmailSubject = 'Email Subject is required';
      } else if (formData.EmailSubject.length > 200) {
        newErrors.EmailSubject = 'Email Subject must be 200 characters or less';
      }
      
      if (!formData.MessageContent || formData.MessageContent.trim() === '') {
        newErrors.MessageContent = 'Message Content is required';
      }
      
      setErrors(newErrors);
      return Object.keys(newErrors).length === 0;
    },
    resetForm: () => {
      setFormDataState({
        Language: 'EN',
        ScheduleFrequency: 'Run Only Once',
        EmailSubject: '',
        Active: true,
        MessageContent: ''
      });
      setErrors({});
    }
  }));

  const handleInputChange = (field, value) => {
    setFormDataState(prev => ({
      ...prev,
      [field]: value
    }));
    
    // Clear error when user starts typing
    if (errors[field]) {
      setErrors(prev => ({
        ...prev,
        [field]: ''
      }));
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (onSave) {
      onSave();
    }
  };
  const languageSelectOptions = languageOptions && languageOptions.length > 0 ? languageOptions : [
    { value: 'English', label: 'English' },
    { value: 'Spanish', label: 'Spanish' },
    { value: 'French', label: 'French' }
  ];
  return (
    <Box className="edit-content-form" sx={{ p: 3, position: 'relative' }}>
      <form onSubmit={handleSubmit}>
        <Grid container spacing={3}>
          {/* Language Field */}
          <Grid item xs={12} md={6}>
            <FAWDropdown
              name="Language"
              label="Language"
              value={formData.Language}
              onChange={async (selectedOption, event) => {
                const newLanguage = selectedOption ? selectedOption.value : '';
                handleInputChange('Language', newLanguage);
                // Call onLanguageChange callback if provided to reload data for new language
                if (onLanguageChange && newLanguage) {
                  await onLanguageChange(newLanguage);
                }
              }}
              options={languageSelectOptions}
              required
              fullWidth
              sx={{
                '& .MuiOutlinedInput-root': {
                  backgroundColor: '#ffffff'
                }
              }}
            />
          </Grid>

          {/* Schedule Frequency Field */}
          <Grid item xs={12} md={6}>
            <FAWInput
              name="ScheduleFrequency"
              label="Schedule Frequency"
              value={formData.ScheduleFrequency}
              onChange={(e) => handleInputChange('ScheduleFrequency', e.target.value)}
              variant="outlined"
              fullWidth
              disabled={true}
              sx={{
                '& .MuiOutlinedInput-root': {
                  backgroundColor: '#f5f5f5'
                }
              }}
            />
          </Grid>

          {/* Email Subject Field */}
          <Grid item xs={12} md={6}>
            <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 1 }}>
              <FAWTypography variant="body2" component="label" sx={{ fontSize: "14px" }}>
                Email Subject
                <RequiredIndicator required={true} />
              </FAWTypography>
              <FAWTypography variant="caption" sx={{ color: '#666' }}>
                {formData.EmailSubject.length}/200
              </FAWTypography>
            </Box>
            <FAWTextarea
              name="EmailSubject"
              label=""
              value={formData.EmailSubject}
              onChange={(e) => handleInputChange('EmailSubject', e.target.value)}
              required
              variant="outlined"
              fullWidth
              rows={6}
              placeholder="Please enter Email Subject"
              error={!!errors.EmailSubject}
              helperText={errors.EmailSubject}
              inputProps={{ maxLength: 200 }}
              sx={{
                width: '100%',
                '& .MuiOutlinedInput-root': {
                  backgroundColor: '#ffffff',
                  width: '100%',
                  maxWidth: '100%'
                },
                '& .MuiOutlinedInput-input': {
                  padding: '8px 12px',
                  width: '100%',
                  maxWidth: '100%',
                  boxSizing: 'border-box'
                },
                '& textarea': {
                  overflowWrap: 'break-word',
                  wordBreak: 'break-word',
                  whiteSpace: 'pre-wrap',
                  width: '100% !important',
                  maxWidth: '100% !important',
                  boxSizing: 'border-box !important',
                  resize: 'none'
                }
              }}
            />
            
            {/* Active Checkbox - positioned under Email Subject */}
            <Box sx={{ mt: 2 }}>
              <FAWCheckbox
                name="Active"
                label="Active"
                checked={formData.Active}
                onChange={(e) => handleInputChange('Active', e.target.checked)}
              />
            </Box>
          </Grid>

          {/* Message Content Field */}
          <Grid item xs={12}>
            <FAWTypography variant="subtitle2" sx={{ mb: 1, fontWeight: 600 }}>
              Message Content
            </FAWTypography>
            <FAWTextEditor
              name="MessageContent"
              value={formData.MessageContent}
              onChange={(value) => handleInputChange('MessageContent', value)}
              height={300}
              placeholder="Enter notification message content..."
              refDomains={refDomains}
              sx={{
                '& .MuiOutlinedInput-root': {
                  backgroundColor: '#ffffff'
                }
              }}
            />
            {errors.MessageContent && (
              <FAWTypography variant="caption" sx={{ color: 'error.main', mt: 1, display: 'block' }}>
                {errors.MessageContent}
              </FAWTypography>
            )}
          </Grid>
        </Grid>
      </form>
    </Box>
  );
});

EditContentForm.displayName = 'EditContentForm';

export default EditContentForm;
