import { useState, useEffect, useCallback, useRef } from 'react';

/**
 * Custom hook for managing EditContentDrawer state
 * Extracts all state management logic to make the component more modular
 */
export const useEditContentState = ({ 
  open, 
  onClose, 
  onSuccess, 
  notificationData, 
  selectedNotificationType,
  languageOptions
}) => {
  // Core state
  const [drawerOpen, setDrawerOpen] = useState(open);
  const [toast, setToast] = useState({ open: false, message: '', type: 'info', duration: 3000 });
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  
  // Form and data state
  const formRef = useRef(null);
  const [initialData, setInitialData] = useState({
    Language: 'English',
    ScheduleFrequency: 'Run Only Once',
    EmailSubject: '',
    Active: true,
    MessageContent: ''
  });
  
  // Confirmation dialog state
  const [confirmationDialog, setConfirmationDialog] = useState({
    open: false,
    title: '',
    message: '',
    onConfirm: null,
    onCancel: null,
    confirmText: 'Save',
    cancelText: 'Cancel',
    severity: 'info'
  });

  // Sync drawer state with external prop
  useEffect(() => {
    setDrawerOpen(open);
  }, [open]);

  // Initialize data when component mounts or notification data changes
  useEffect(() => { 
    if (notificationData && selectedNotificationType) {
      // Ensure language is a code, not a display name
      let languageCode = notificationData.language || 'EN';
      
      // If languageOptions are available, try to match and get the code
      if (languageOptions && languageOptions.length > 0 && notificationData.language) {
        // Check if it's already a code (2-3 uppercase letters)
        const isCodeFormat = /^[A-Z]{2,3}$/.test(notificationData.language);
        
        if (!isCodeFormat) {
          // It's likely a display name, find the corresponding code from languageOptions
          const matchingOption = languageOptions.find(opt => 
            opt.label?.toLowerCase() === notificationData.language?.toLowerCase() ||
            opt.value?.toLowerCase() === notificationData.language?.toLowerCase()
          );
          
          if (matchingOption) {
            languageCode = matchingOption.value;
          }
        } else {
          // Verify the code exists in languageOptions
          const codeExists = languageOptions.find(opt => opt.value === notificationData.language);
          if (!codeExists && languageOptions.length > 0) {
            // Code doesn't exist, default to first option
            languageCode = languageOptions[0].value;
          }
        }
      }

      const newInitialData = {
        Language: languageCode,
        ScheduleFrequency: notificationData.scheduleFrequency || 'Run Only Once',
        EmailSubject: notificationData.subject || '',
        Active: notificationData.isActive === true,
        MessageContent: notificationData.message || ''
      };
      setInitialData(newInitialData);
    } else {
    }
  }, [notificationData, selectedNotificationType, languageOptions]);

  // Show toast notification
  const showToast = useCallback((message, type = 'info', duration = 3000) => {
    setToast({ open: true, message, type, duration });
  }, []);

  // Hide toast notification
  const hideToast = useCallback(() => {
    setToast(prev => ({ ...prev, open: false }));
  }, []);

  // Show confirmation dialog
  const showConfirmation = useCallback((title, message, onConfirm, options = {}) => {
    setConfirmationDialog({
      open: true,
      title,
      message,
      onConfirm,
      onCancel: () => setConfirmationDialog(prev => ({ ...prev, open: false })),
      confirmText: options.confirmText || 'Save',
      cancelText: options.cancelText || 'Cancel',
      severity: options.severity || 'info'
    });
  }, []);

  // Hide confirmation dialog
  const hideConfirmation = useCallback(() => {
    setConfirmationDialog(prev => ({ ...prev, open: false }));
  }, []);

  return {
    // State
    drawerOpen,
    setDrawerOpen,
    toast,
    setToast,
    saving,
    setSaving,
    loading,
    setLoading,
    error,
    setError,
    initialData,
    setInitialData,
    confirmationDialog,
    setConfirmationDialog,
    formRef,
    
    // Actions
    showToast,
    hideToast,
    showConfirmation,
    hideConfirmation
  };
};
